def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    from functools import lru_cache

    @lru_cache(maxsize=None)
    def popcount(x: int) -> int:
        return bin(x).count('1')

    @lru_cache(maxsize=None)
    def get_depth(x: int) -> int:
        if x == 1:
            return 0
        return 1 + get_depth(popcount(x))

    # Precompute depths for all nums initially
    depth = [get_depth(num) for num in nums]

    answer = []

    for query in queries:
        if query[0] == 1:
            _, l, r, k = query
            count = 0
            for i in range(l, r + 1):
                if depth[i] == k:
                    count += 1
            answer.append(count)
        elif query[0] == 2:
            _, idx, val = query
            nums[idx] = val
            # Clear the cache if needed (though lru_cache handles it)
            depth[idx] = get_depth(val)

    return answer
